import { Col, Row, Table, Tag } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import SpinCustom from "src/components/SpinCustom"
import { SYSTEM_KEY } from "src/constants/constants"
import { formatPrice, getSystemKeyDescription } from "src/lib/utils"
import MembershipPackageService from "src/services/MembershipPackageService"
import "../styles/viewMemberType.scss"

function ModalViewMemberType({ open, onCancel, data }) {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [loading, setLoading] = useState(false)
  const [packageDetails, setPackageDetails] = useState([])

  const fetchRankDetails = async listMemberRanks => {
    setLoading(true)

    try {
      const rankPromises = listMemberRanks.map(async rank => {
        const memberRankID = typeof rank === "string" ? rank : rank.MemberRankID

        try {
          const res = await MembershipPackageService.getRankById({
            MemberRankID: memberRankID,
          })
          return res.Object
        } catch (error) {
          console.error(`Error fetching rank ${memberRankID}:`, error)
        }
      })

      const rankData = await Promise.all(rankPromises)
      console.log("Final rank data:", rankData)
      return rankData
    } catch (error) {
      console.error("Error fetching rank details:", error)
      return []
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    const loadPackageDetails = async () => {
      if (data?.listMemberRanks) {
        const details = await fetchRankDetails(data.listMemberRanks)
        setPackageDetails(details)
      }
    }

    if (open && data) {
      loadPackageDetails()
    }
  }, [open, data])

  const getObjectText = value => {
    const result = getSystemKeyDescription(
      SYSTEM_KEY?.RANK_OBJECT,
      value,
      listSystemKey,
    )
    return result || "Không xác định"
  }

  const getStatusName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.STATUS, value, listSystemKey)

  const getMemberTypeName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.MEMBER_TYPE, value, listSystemKey)

  const renderPackageDetails = () => {
    if (!packageDetails || packageDetails.length === 0) {
      return (
        <div className="modal-view-member__empty-benefits">
          <span>Chưa có quyền lợi nào</span>
        </div>
      )
    }

    return (
      <div className="modal-view-member__benefits-container">
        <div className="modal-view-member__benefits-header">
          Danh sách quyền lợi ({packageDetails.length}):
        </div>

        {packageDetails.map((pkg, index) => (
          <div
            key={pkg.MemberRankID}
            className={`modal-view-member__benefit-item ${
              index < packageDetails.length - 1
                ? "modal-view-member__benefit-item--border"
                : ""
            }`}
          >
            <div className="modal-view-member__benefit-header">
              <span className="modal-view-member__benefit-name">
                {pkg.RankName}
              </span>
              <Tag
                color={pkg.Status === 1 ? "green" : "red"}
                size="small"
                className="modal-view-member__benefit-status"
              >
                {getStatusName(pkg.Status)}
              </Tag>
            </div>

            <Row gutter={[16, 8]} className="modal-view-member__benefit-info">
              <Col span={12}>
                <div className="modal-view-member__info-item">
                  <strong>Đối tượng:</strong>
                  <span className="modal-view-member__info-value modal-view-member__info-value--object">
                    {getObjectText(pkg.RankObject)}
                  </span>
                </div>
              </Col>
              <Col span={12}>
                <div className="modal-view-member__info-item">
                  <strong>Chiết khấu:</strong>
                  <span className="modal-view-member__info-value modal-view-member__info-value--discount">
                    {pkg.RankDiscount}%
                  </span>
                </div>
              </Col>
            </Row>

            {pkg.RankInterest && (
              <div className="modal-view-member__interest-section">
                <div className="modal-view-member__interest-label">
                  <strong>Lợi ích:</strong>
                </div>
                <div className="modal-view-member__interest-content">
                  {pkg.RankInterest}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    )
  }

  if (!open || !data) return null

  return (
    <CustomModal
      title={`Chi tiết loại hội viên: ${data.PackageName || "N/A"}`}
      visible={!!open}
      width={1000}
      onCancel={onCancel}
      footer={
        <div className="modal-view-member__footer">
          <Button btnType="secondary" onClick={onCancel}>
            Đóng
          </Button>
        </div>
      }
      className="modal-view-member"
    >
      <SpinCustom spinning={loading}>
        <div className="modal-view-member__content">
          <Table
            bordered
            pagination={false}
            showHeader={false}
            className="modal-view-member__table"
            dataSource={[
              {
                key: 1,
                label: "Tên loại hội viên",
                value: (
                  <span className="modal-view-member__package-name">
                    {data.PackageName || "N/A"}
                  </span>
                ),
              },
              {
                key: 2,
                label: "Loại tài khoản",
                value: (
                  <span className="modal-view-member__member-type">
                    {getMemberTypeName(data.MemberType)}
                  </span>
                ),
              },
              {
                key: 3,
                label: "Hội phí",
                value: (
                  <span className="modal-view-member__price">
                    {formatPrice(data.Price)}
                  </span>
                ),
              },
              {
                key: 4,
                label: "Trạng thái",
                value: (
                  <Tag
                    color={data.Status === 1 ? "green" : "red"}
                    className="modal-view-member__status-tag"
                  >
                    {getStatusName(data.Status)}
                  </Tag>
                ),
              },
              {
                key: 5,
                label: "Quyền lợi",
                value: renderPackageDetails(),
              },
            ]}
            columns={[
              {
                dataIndex: "label",
                width: "25%",
                render: text => (
                  <strong className="modal-view-member__table-label">
                    {text}
                  </strong>
                ),
              },
              {
                dataIndex: "value",
                width: "75%",
                render: value => (
                  <div className="modal-view-member__table-value">{value}</div>
                ),
              },
            ]}
            rowClassName={(record, index) =>
              record.key === 5 ? "modal-view-member__package-details-row" : ""
            }
          />
        </div>
      </SpinCustom>
    </CustomModal>
  )
}

export default ModalViewMemberType
