// ModalSelectPackages.js
import { Col, Input, Row, Select, Table } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import { SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey, getSystemKeyDescription } from "src/lib/utils"
import MembershipPackageService from "src/services/MembershipPackageService"

const { Option } = Select

function ModalSelectPackages({ open, onCancel, onOk, selectedPackages = [] }) {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [allSelectedKeys, setAllSelectedKeys] = useState([])
  const [selectedRowKeys, setSelectedRowKeys] = useState([])
  const [loading, setLoading] = useState(false)
  const [loadingData, setLoadingData] = useState(false)
  const [packageData, setPackageData] = useState([])
  const [filteredData, setFilteredData] = useState([])
  const [totalRecords, setTotalRecords] = useState(0)

  const [textSearch, setTextSearch] = useState("")
  const [statusFilter, setStatusFilter] = useState("")
  const [rankObjectFilter, setRankObjectFilter] = useState("")
  const [pagination, setPagination] = useState({
    PageSize: 10,
    CurrentPage: 1,
  })

  const columns = [
    {
      title: "Tên quyền lợi",
      dataIndex: "RankName",
      key: "RankName",

      render: text => <span style={{ fontWeight: 500 }}>{text}</span>,
    },
    {
      title: "Đối tượng",
      dataIndex: "RankObject",
      key: "RankObject",
      align: "center",
      render: value => getRankObjectName(value),
    },
    {
      title: "Chiết khấu",
      dataIndex: "RankDiscount",
      key: "RankDiscount",

      align: "center",
      render: value => (value ? `${value}%` : "-"),
    },
    // {
    //   title: "Thời hạn",
    //   dataIndex: "RankDuration",
    //   key: "RankDuration",
    //   width: "15%",
    //   align: "center",
    //   render: (duration, record) => {
    //     if (!duration) return "-";
    //     const unitText = getDurationUnitText(record.DurationUnit);
    //     return `${duration} ${unitText}`;
    //   },
    // },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: "Status",

      align: "center",
      render: value => (
        <span
          style={{
            color: value === 1 ? "#52c41a" : "#ff4d4f",
            fontWeight: 500,
          }}
        >
          {getStatusName(value)}
        </span>
      ),
    },
  ]

  const rowSelection = {
    selectedRowKeys,
    onChange: selectedKeys => {
      setAllSelectedKeys(prev => {
        const currentKeys = filteredData.map(pkg => pkg.MemberRankID)
        const preservedKeys = prev.filter(key => !currentKeys.includes(key))
        return [...new Set([...preservedKeys, ...selectedKeys])]
      })
      setSelectedRowKeys(selectedKeys)
    },
    getCheckboxProps: record => ({
      name: record.RankName,
      disabled: record.Status !== 1,
    }),
  }

  const getStatusName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.STATUS, value, listSystemKey)

  const getRankObjectName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.RANK_OBJECT, value, listSystemKey)

  // const getDurationUnitText = value =>
  //   getSystemKeyDescription(SYSTEM_KEY?.DURATION_UNIT, value, listSystemKey);

  const fetchPackageData = async () => {
    try {
      setLoadingData(true)
      const params = {
        TextSearch: textSearch.trim(),
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
      }

      if (statusFilter) {
        params.Status = Number(statusFilter)
      }

      if (rankObjectFilter) {
        params.RankObject = Number(rankObjectFilter)
      }

      const response = await MembershipPackageService.getListRank(params)

      if (response?.isError) {
        Notice({
          msg: response?.message || "Có lỗi xảy ra khi tải dữ liệu",
          isSuccess: false,
        })
        return
      }

      const { ListData = [], TotalCount = 0 } = response?.Object || {}
      setPackageData(ListData)
      setFilteredData(ListData)
      setTotalRecords(TotalCount)
    } catch (error) {
      console.error("Error fetching package data:", error)
      Notice({
        msg: "Có lỗi xảy ra khi tải dữ liệu quyền lợi",
        isSuccess: false,
      })
    } finally {
      setLoadingData(false)
    }
  }

  const handleSubmit = async () => {
    try {
      setLoading(true)
      const allSelectedData = []

      const currentPageData = packageData.filter(pkg =>
        allSelectedKeys.includes(pkg.MemberRankID),
      )
      allSelectedData.push(...currentPageData)

      const missingKeys = allSelectedKeys.filter(
        key => !packageData.some(pkg => pkg.MemberRankID === key),
      )

      if (missingKeys.length > 0) {
        try {
          const missingDataPromises = missingKeys.map(async key => {
            const response = await MembershipPackageService.getRankById({
              MemberRankID: key,
            })
            return response?.Object
          })

          const missingData = await Promise.all(missingDataPromises)
          const validMissingData = missingData.filter(
            item => item !== null && item !== undefined,
          )
          allSelectedData.push(...validMissingData)
        } catch (error) {
          console.error("Error fetching missing data:", error)
        }
      }

      if (allSelectedData.length === 0) {
        Notice({
          msg: "Vui lòng chọn ít nhất một quyền lợi",
          isSuccess: false,
        })
        return
      }

      const result = {
        names: allSelectedData.map(pkg => pkg.RankName),
        data: allSelectedData,
        memberRankIds: allSelectedData.map(pkg => pkg.MemberRankID),
      }

      onOk(result)

      Notice({
        msg: `Đã chọn ${allSelectedData.length} quyền lợi`,
        isSuccess: true,
      })
    } catch (error) {
      console.error("Error selecting packages:", error)
      Notice({
        msg: "Có lỗi xảy ra khi cập nhật quyền lợi",
        isSuccess: false,
      })
    } finally {
      setLoading(false)
    }
  }

  const handleCancel = () => {
    onCancel()
  }

  const calculateSelectedCount = () => {
    return allSelectedKeys.length
  }

  const handleSearch = () => {
    setPagination(prev => ({ ...prev, CurrentPage: 1 }))
  }

  const handleFilterChange = () => {
    setPagination(prev => ({ ...prev, CurrentPage: 1 }))
  }

  useEffect(() => {
    if (open) {
      let selectedKeys = []

      if (Array.isArray(selectedPackages) && selectedPackages.length > 0) {
        if (
          typeof selectedPackages[0] === "object" &&
          selectedPackages[0]?.MemberRankID
        ) {
          selectedKeys = selectedPackages.map(pkg => pkg.MemberRankID)
        } else if (
          typeof selectedPackages[0] === "string" ||
          typeof selectedPackages[0] === "number"
        ) {
          selectedKeys = selectedPackages
        }
      }

      console.log("Setting initial selected keys:", selectedKeys)
      setAllSelectedKeys(selectedKeys)
    }
  }, [open, selectedPackages])

  useEffect(() => {
    if (open) {
      fetchPackageData()
    }
  }, [open, pagination, textSearch, statusFilter, rankObjectFilter])

  useEffect(() => {
    if (filteredData.length > 0) {
      const currentPageSelectedKeys = allSelectedKeys.filter(key =>
        filteredData.some(pkg => pkg.MemberRankID === key),
      )
      setSelectedRowKeys(currentPageSelectedKeys)
    }
  }, [filteredData, allSelectedKeys])

  useEffect(() => {
    if (open) {
      setTextSearch("")
      setStatusFilter("")
      setRankObjectFilter("")
      setPagination({ PageSize: 10, CurrentPage: 1 })
    }
  }, [open])

  return (
    <CustomModal
      title="Chọn quyền lợi hội viên"
      visible={open}
      width={1200}
      onCancel={handleCancel}
      footer={
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <div style={{ display: "flex", gap: 8 }}>
            <Button btnType="secondary" onClick={handleCancel}>
              Hủy
            </Button>
            <Button
              btnType="primary"
              onClick={handleSubmit}
              loading={loading}
              disabled={calculateSelectedCount() === 0}
            >
              Chọn ({calculateSelectedCount()})
            </Button>
          </div>
        </div>
      }
    >
      <SpinCustom spinning={loadingData}>
        <Row gutter={[16, 16]} style={{ marginBottom: 16 }}>
          <Col flex="400px">
            <Input.Search
              placeholder="Tìm kiếm theo tên quyền lợi..."
              allowClear
              value={textSearch}
              onChange={e => setTextSearch(e.target.value)}
              onSearch={handleSearch}
            />
          </Col>
          <Col lg={6} xs={12}>
            <SelectCustom
              placeholder="Chọn đối tượng"
              value={rankObjectFilter}
              onChange={value => {
                setRankObjectFilter(value)
                handleFilterChange()
              }}
            >
              <Option value="">Tất cả</Option>
              {getListComboByKey(SYSTEM_KEY?.RANK_OBJECT, listSystemKey)?.map(
                i => (
                  <Option key={i.CodeValue} value={i.CodeValue}>
                    {i.Description}
                  </Option>
                ),
              )}
            </SelectCustom>
          </Col>
          <Col lg={6} xs={12}>
            <SelectCustom
              placeholder="Chọn trạng thái"
              value={statusFilter}
              onChange={value => {
                setStatusFilter(value)
                handleFilterChange()
              }}
            >
              <Option value="">Tất cả</Option>
              {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(i => (
                <Option key={i.CodeValue} value={i.CodeValue}>
                  {i.Description}
                </Option>
              ))}
            </SelectCustom>
          </Col>
        </Row>

        <div>
          <Table
            rowSelection={rowSelection}
            columns={columns}
            dataSource={filteredData}
            loading={loadingData}
            pagination={{
              current: pagination.CurrentPage,
              pageSize: pagination.PageSize,
              total: totalRecords,
              onChange: (CurrentPage, PageSize) => {
                setPagination({
                  ...pagination,
                  CurrentPage,
                  PageSize,
                })
              },
            }}
            bordered
            size="middle"
            rowKey="MemberRankID"
            // scroll={{ y: 400 }}
            locale={{
              emptyText: loadingData ? "Đang tải..." : "Không có dữ liệu",
            }}
          />
        </div>
      </SpinCustom>
    </CustomModal>
  )
}

export default ModalSelectPackages
