import { Col, Form, Row, Spin } from "antd"
import { useEffect, useState } from "react"
import InputCustom from "src/components/Input/InputCustom"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import MembershipTypeService from "src/services/MembershipTypeService"
import MembershipPackageService from "src/services/MembershipPackageService"
import ModalSelectPackages from "./ModalSelectPackages"
import { getListComboByKey, getSystemKeyDescription } from "src/lib/utils"
import { useSelector } from "react-redux"
import { SYSTEM_KEY } from "src/constants/constants"
import "../styles/insertUpdateType.scss"

function ModalInsertUpdateType({ open, onCancel, onOk }) {
  const { listSystemKey } = useSelector(state => state.appGlobal)

  const [form] = Form.useForm()
  const [loading, setLoading] = useState(false)
  const [showSelectPackages, setShowSelectPackages] = useState(false)
  const [selectedPackages, setSelectedPackages] = useState({
    names: [],
    data: [],
    memberRankIds: [],
  })

  // Xác định mode
  const isEditMode = open?.PackageID
  const isCreateMode = open === true

  const fetchRankDetails = async listMemberRanks => {
    if (
      !listMemberRanks ||
      !Array.isArray(listMemberRanks) ||
      listMemberRanks.length === 0
    ) {
      return {
        names: [],
        data: [],
        memberRankIds: [],
      }
    }

    try {
      setLoading(true)
      const rankPromises = listMemberRanks.map(async rank => {
        try {
          const res = await MembershipPackageService.getRankById({
            MemberRankID: rank.MemberRankID,
          })

          if (res?.isError || !res?.Object) {
            return {
              MemberRankID: rank.MemberRankID,
              RankName: "Quyền lợi không xác định",
              RankObject: 1,
              RankDiscount: 0,
              RankInterest: "",
              Status: 1,
            }
          }

          return res.Object
        } catch (error) {
          console.error(`Error fetching rank ${rank.MemberRankID}:`, error)
          return {
            MemberRankID: rank.MemberRankID,
            RankName: "Quyền lợi lỗi",
            RankObject: 1,
            RankDiscount: 0,
            RankInterest: "",
            Status: 1,
          }
        }
      })

      const rankData = await Promise.all(rankPromises)
      const validRankData = rankData.filter(rank => rank !== null)

      return {
        names: validRankData.map(rank => rank.RankName),
        data: validRankData,
        memberRankIds: validRankData.map(rank => rank.MemberRankID),
      }
    } catch (error) {
      console.error("Error fetching rank details:", error)
      return {
        names: [],
        data: [],
        memberRankIds: [],
      }
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    const initializeModal = async () => {
      if (isEditMode) {
        form.setFieldsValue({
          PackageName: open.PackageName,
          Price: open.Price,
          MemberType: open.MemberType,
          Status: open.Status,
        })

        if (open.listMemberRanks && Array.isArray(open.listMemberRanks)) {
          const updatedPackages = await fetchRankDetails(open.listMemberRanks)
          setSelectedPackages(updatedPackages)
        } else {
          setSelectedPackages({
            names: [],
            data: [],
            memberRankIds: [],
          })
        }
      } else if (isCreateMode) {
        form.resetFields()
        form.setFieldsValue({
          Status: 1,
          MemberType: 1,
        })
        setSelectedPackages({
          names: [],
          data: [],
          memberRankIds: [],
        })
      }
    }

    if (open) {
      initializeModal()
    }
  }, [open, form, isEditMode, isCreateMode])

  const handleSelectPackages = () => {
    setShowSelectPackages(true)
  }

  const handlePackagesSelected = packagesResult => {
    if (!packagesResult || !packagesResult.data) {
      Notice({
        msg: "Dữ liệu quyền lợi không hợp lệ",
        isSuccess: false,
      })
      return
    }

    setSelectedPackages({
      names: packagesResult.data.map(pkg => pkg.RankName),
      data: packagesResult.data,
      memberRankIds: packagesResult.data.map(pkg => pkg.MemberRankID),
    })

    setShowSelectPackages(false)

    Notice({
      msg: `Đã chọn ${packagesResult.data.length} quyền lợi`,
      isSuccess: true,
    })
  }

  const handleRemovePackage = packageToRemove => {
    const updatedData = selectedPackages.data.filter(
      pkg => pkg.MemberRankID !== packageToRemove.MemberRankID,
    )
    const updatedNames = updatedData.map(pkg => pkg.RankName)
    const updatedMemberRankIds = updatedData.map(pkg => pkg.MemberRankID)

    const updatedPackages = {
      names: updatedNames,
      data: updatedData,
      memberRankIds: updatedMemberRankIds,
    }

    setSelectedPackages(updatedPackages)

    Notice({
      msg: `Đã xóa quyền lợi "${packageToRemove.RankName}"`,
      isSuccess: true,
    })
  }

  const getObjectText = value => {
    if (!value && value !== 0) {
      return "Không xác định"
    }

    const result = getSystemKeyDescription(
      SYSTEM_KEY?.RANK_OBJECT,
      value,
      listSystemKey,
    )
    return result || "Không xác định"
  }

  const handleSubmit = async () => {
    try {
      const values = await form.validateFields()
      setLoading(true)

      if (
        !selectedPackages.memberRankIds ||
        selectedPackages.memberRankIds.length === 0
      ) {
        Notice({
          msg: "Vui lòng chọn ít nhất một quyền lợi",
          isSuccess: false,
        })
        setLoading(false)
        return
      }

      const requestData = {
        PackageName: values.PackageName,
        Status: values.Status,
        MemberType: values.MemberType,
        Price: Number(values.Price) || 0,
        listMemberRanks: selectedPackages.memberRankIds,
      }

      let response

      if (isEditMode) {
        requestData.PackageID = open.PackageID
        response = await MembershipTypeService.updatePackage(requestData)
      } else {
        response = await MembershipTypeService.insertPacakge(requestData)
      }

      if (response?.isError) {
        Notice({
          msg: response?.message || "Có lỗi xảy ra khi xử lý dữ liệu.",
          isSuccess: false,
        })
        return
      }

      Notice({
        msg: isEditMode
          ? "Cập nhật loại hội viên thành công"
          : "Thêm mới loại hội viên thành công",
        isSuccess: true,
      })
      onOk()
      onCancel()
    } catch (error) {
      console.error("Form validation failed:", error)
      Notice({
        msg: "Vui lòng kiểm tra lại thông tin đã nhập.",
        isSuccess: false,
      })
    } finally {
      setLoading(false)
    }
  }

  if (!open) return null

  return (
    <>
      <CustomModal
        title={
          isEditMode ? "Sửa thông tin loại hội viên" : "Thêm loại hội viên"
        }
        visible={!!open}
        width={720}
        onCancel={onCancel}
        footer={
          <div className="modal-footer">
            <Button btnType="secondary" onClick={onCancel}>
              Hủy
            </Button>
            <Button btnType="primary" onClick={handleSubmit} loading={loading}>
              {isEditMode ? "Cập nhật" : "Thêm mới"}
            </Button>
          </div>
        }
      >
        <Spin spinning={loading}>
          <Form form={form} layout="vertical">
            <Row gutter={[16, 16]}>
              <Col span={24}>
                <Form.Item
                  name="PackageName"
                  label="Tên loại hội viên"
                  rules={[
                    {
                      required: true,
                      message: "Vui lòng nhập tên loại hội viên",
                    },
                  ]}
                >
                  <InputCustom placeholder="Nhập tên loại hội viên" />
                </Form.Item>
              </Col>

              <Col span={12}>
                <Form.Item
                  name="MemberType"
                  label="Loại tài khoản"
                  rules={[
                    { required: true, message: "Vui lòng chọn loại tài khoản" },
                  ]}
                >
                  <SelectCustom placeholder="Chọn loại tài khoản">
                    {getListComboByKey(
                      SYSTEM_KEY?.MEMBER_TYPE,
                      listSystemKey,
                    )?.map(item => (
                      <SelectCustom.Option
                        key={item.ID}
                        value={Number(item.CodeValue)}
                      >
                        {item.Description}
                      </SelectCustom.Option>
                    ))}
                  </SelectCustom>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item
                  name="Status"
                  label="Trạng thái"
                  rules={[
                    { required: true, message: "Vui lòng chọn trạng thái" },
                  ]}
                >
                  <SelectCustom placeholder="Chọn trạng thái">
                    {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(
                      item => (
                        <SelectCustom.Option
                          key={item.ID}
                          value={Number(item.CodeValue)}
                        >
                          {item.Description}
                        </SelectCustom.Option>
                      ),
                    )}
                  </SelectCustom>
                </Form.Item>
              </Col>

              <Col span={24}>
                <Form.Item
                  name="Price"
                  label="Hội phí"
                  rules={[
                    { required: true, message: "Vui lòng nhập hội phí" },
                    {
                      type: "number",
                      min: 0,
                      message: "Hội phí phải lớn hơn hoặc bằng 0",
                      transform: value => Number(value),
                    },
                  ]}
                >
                  <InputCustom
                    placeholder="Nhập hội phí"
                    suffix="VNĐ"
                    type="number"
                  />
                </Form.Item>
              </Col>

              <Col span={24}>
                <Form.Item label="Quyền lợi" required>
                  <div className="benefits-section">
                    <div className="benefits-selector">
                      <InputCustom
                        placeholder="Chưa chọn quyền lợi nào"
                        value={selectedPackages.names?.join(", ") || ""}
                        readOnly
                        className="benefits-input"
                      />
                      <Button
                        btnType="primary"
                        onClick={handleSelectPackages}
                        className="select-benefits-btn"
                      >
                        Chọn quyền lợi
                      </Button>
                    </div>

                    {selectedPackages.data &&
                      selectedPackages.data.length > 0 && (
                        <div className="selected-benefits-container">
                          <div className="selected-benefits-header">
                            Các quyền lợi đã chọn (
                            {selectedPackages.data.length}):
                          </div>

                          {selectedPackages.data.map((pkg, index) => (
                            <div
                              key={pkg.MemberRankID}
                              className={`benefit-item ${
                                index < selectedPackages.data.length - 1
                                  ? "with-margin"
                                  : ""
                              }`}
                            >
                              <div className="benefit-content">
                                <div className="benefit-name">
                                  {pkg.RankName}
                                </div>
                                <div className="benefit-details">
                                  <div className="benefit-meta">
                                    <span className="benefit-object">
                                      Đối tượng:{" "}
                                      <strong>
                                        {getObjectText(pkg.RankObject)}
                                      </strong>
                                    </span>
                                    <span className="benefit-discount">
                                      Chiết khấu:{" "}
                                      <strong>{pkg.RankDiscount}%</strong>
                                    </span>
                                  </div>
                                  {pkg.RankInterest && (
                                    <div className="benefit-interest">
                                      <strong>Lợi ích:</strong>{" "}
                                      <em>{pkg.RankInterest}</em>
                                    </div>
                                  )}
                                </div>
                              </div>
                              <div className="benefit-actions">
                                <Button
                                  btnType="danger"
                                  size="small"
                                  onClick={() => handleRemovePackage(pkg)}
                                  className="remove-benefit-btn"
                                >
                                  Xóa
                                </Button>
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                  </div>
                </Form.Item>
              </Col>
            </Row>
          </Form>
        </Spin>
      </CustomModal>

      <ModalSelectPackages
        open={showSelectPackages}
        onCancel={() => setShowSelectPackages(false)}
        onOk={handlePackagesSelected}
        selectedPackages={selectedPackages.data || []}
      />
    </>
  )
}

export default ModalInsertUpdateType
