import { Col, Row, Select } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import SpanText from "src/components/Typography/SpanText"
import { hideOnSinglePage, SYSTEM_KEY } from "src/constants/constants"
import {
  formatPrice,
  getListComboByKey,
  getSystemKeyDescription,
} from "src/lib/utils"
import MembershipTypeService from "src/services/MembershipTypeService"
import ModalInsertUpdateType from "./modal/ModalInsertUpdateType"
import ModalViewMemberType from "./modal/ModalViewMemberType"

const { Option } = Select

const MembershipType = () => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [pagination, setPagination] = useState({
    PageSize: 10,
    CurrentPage: 1,
    Status: "",
    MemberType: "",
    textSearch: "",
  })
  const [textSearch, setTextSearch] = useState("")
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState([])
  const [totalRecords, setTotalRecords] = useState(0)
  const [openModalView, setOpenModalView] = useState(false)
  const [openModalInsertUpdate, setOpenModalInsertUpdate] = useState(false)

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      render: (_, __, idx) =>
        idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1),
      width: 70,
      align: "center",
    },
    {
      title: "Loại hội viên",
      dataIndex: "PackageName",
      width: 400,
    },
    {
      title: "Loại tài khoản",
      dataIndex: "MemberType",
      align: "center",
      render: val => getMemberTypeName(val),
    },
    {
      title: "Quyền lợi",
      dataIndex: "listMemberRanks",
      align: "left",
      render: val => {
        if (!val || !Array.isArray(val) || val.length === 0) {
          return (
            <span className="membership-type__benefits--empty">
              Chưa có quyền lợi
            </span>
          )
        }

        return (
          <div className="membership-type__benefits">
            {val.map((rank, index) => (
              <div
                key={rank.MemberRankID || index}
                className="membership-type__benefits-item"
              >
                <span className="membership-type__benefits-text">
                  • {rank.RankName || "Quyền lợi không xác định"}
                </span>
              </div>
            ))}
          </div>
        )
      },
    },
    {
      title: "Hội phí",
      dataIndex: "Price",
      align: "center",
      render: val => (val ? formatPrice(val) : "-"),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      align: "center",
      width: 160,
      render: (isStatus, record) => {
        const statusName = getStatusName(isStatus)
        const isActive = isStatus === 1

        return (
          <div className="membership-type__status">
            <div className="membership-type__status-text fw-600">
              <SpanText type={isActive ? "success" : "danger"}>
                {statusName}
              </SpanText>
            </div>

            <FloatActionWrapper size="small" className="float-action__wrapper">
              <ButtonCircle
                className="button-circle membership-type__btn-edit"
                title="Chỉnh sửa"
                iconName="edit"
                onClick={e => {
                  e.stopPropagation()
                  setOpenModalInsertUpdate(record)
                }}
              />
              <ButtonCircle
                className="button-circle membership-type__btn-delete"
                title="Xoá"
                iconName="deleteRow"
                onClick={e => {
                  e.stopPropagation()
                  handleDeleteConfirm(record)
                }}
              />
            </FloatActionWrapper>
          </div>
        )
      },
    },
  ]

  const getStatusName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.STATUS, value, listSystemKey)

  const getMemberTypeName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.MEMBER_TYPE, value, listSystemKey)

  const getList = async () => {
    try {
      setLoading(true)
      const params = {
        TextSearch: textSearch.trim(),
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
      }

      if (pagination.Status) params.Status = Number(pagination.Status)

      if (pagination.MemberType)
        params.MemberType = Number(pagination.MemberType)

      const res = await MembershipTypeService.getListPackage(params)
      if (res?.isError) return

      const { ListPackage = [], TotalCount = 0 } = res?.Object || {}

      setListData(ListPackage)
      setTotalRecords(TotalCount)
    } finally {
      setLoading(false)
    }
  }
  const deleteRank = async id => {
    try {
      const res = await MembershipTypeService.deletePackage([id])
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Xóa gói thành viên thành công!",
      })
    } catch (error) {
      console.log("Có lỗi xảy ra khi xóa gói thành viên:", error)
      Notice({
        isSuccess: false,
        msg: "Có lỗi xảy ra khi xóa gói thành viên!",
      })
    }
  }
  const handleDeleteConfirm = record => {
    CB1({
      title: `Bạn có chắc chắn muốn xoá gói <strong>"${record.PackageName}"</strong> không?`,
      icon: "warning-usb",
      okText: "Đồng ý",
      cancelText: "Hủy",
      width: 500,
      warningTitle: true,
      okButtonProps: {
        style: {
          background: "#ff4d4f",
          borderColor: "#ff4d4f",
        },
      },
      onOk: close => {
        deleteRank(record.PackageID)
        close()
      },
    })
  }

  useEffect(() => {
    if (pagination) getList()
  }, [pagination])

  useEffect(() => {
    const timeoutId = setTimeout(() => {
      setPagination(prev => ({
        ...prev,
        textSearch: textSearch,
        CurrentPage: 1,
      }))
    }, 300)

    return () => clearTimeout(timeoutId)
  }, [textSearch])

  return (
    <SpinCustom spinning={loading}>
      <div className="membership-type">
        <Row className="title-type-1 justify-content-space-between align-items-center ">
          <div className="">Danh sách loại hội viên ({totalRecords}):</div>
          <ButtonCustom
            btnType="primary"
            className="btn-hover-shadow membership-type__btn-add"
            onClick={() => setOpenModalInsertUpdate(true)}
          >
            Thêm mới
          </ButtonCustom>
        </Row>
        <Row
          gutter={[16, 16]}
          className="align-items-center pb-8 pt-0 mb-16 mt-16"
          align="middle"
        >
          <Col flex="1 1 500px" style={{ minWidth: "400px" }}>
            <InputCustom
              type="search"
              allowClear
              label="Tìm kiếm theo tên gói"
              enterButton
              onSearch={() =>
                setPagination(pre => ({ ...pre, CurrentPage: 1 }))
              }
              onChange={e => setTextSearch(e?.target?.value)}
            />
          </Col>
          <Col flex="0 0 200px">
            <SelectCustom
              label="Loại tài khoản"
              value={pagination.MemberType}
              onChange={MemberType => {
                setPagination(pre => ({
                  ...pre,
                  MemberType,
                  CurrentPage: 1,
                }))
              }}
            >
              <Option value="">Tất cả</Option>
              {getListComboByKey(SYSTEM_KEY?.MEMBER_TYPE, listSystemKey)?.map(
                i => (
                  <Option key={i.CodeValue} value={i.CodeValue}>
                    {i.Description}
                  </Option>
                ),
              )}
            </SelectCustom>
          </Col>
          <Col flex="0 0 180px">
            <SelectCustom
              label="Trạng thái"
              value={pagination.Status}
              onChange={Status => {
                setPagination(pre => ({ ...pre, Status, CurrentPage: 1 }))
              }}
            >
              <Option value="">Tất cả</Option>
              {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(i => (
                <Option key={i.CodeValue} value={i.CodeValue}>
                  {i.Description}
                </Option>
              ))}
            </SelectCustom>
          </Col>
        </Row>

        <TableCustom
          isPrimary
          dataSource={listData}
          columns={columns}
          sticky={{ offsetHeader: -12 }}
          loading={loading}
          textEmpty="Không có gói hội viên nào!"
          pagination={{
            hideOnSinglePage: totalRecords <= hideOnSinglePage,
            current: pagination?.CurrentPage,
            pageSize: pagination?.PageSize,
            responsive: true,
            total: totalRecords,
            locale: { items_per_page: "" },
            showSizeChanger: totalRecords > 10,
            onChange: (CurrentPage, PageSize) => {
              setPagination({
                ...pagination,
                CurrentPage,
                PageSize,
              })
            },
          }}
          rowKey="PackageID"
          onRow={record => ({
            onClick: () => {
              setOpenModalView(record)
            },
          })}
        />

        {openModalView && (
          <ModalViewMemberType
            open={!!openModalView}
            onCancel={() => setOpenModalView(false)}
            data={openModalView}
          />
        )}
        {openModalInsertUpdate && (
          <ModalInsertUpdateType
            open={openModalInsertUpdate}
            onOk={getList}
            onCancel={() => setOpenModalInsertUpdate(false)}
          />
        )}
      </div>
    </SpinCustom>
  )
}

export default MembershipType
